; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		addressmode.asm
;		Purpose:	Identify the address mode/operand for the post opcode part of the instruction.
;		Created:	17th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;					Work out the address mode from X , store in AXAddrMode
;						   CC if okay, CS if error with error in A.
;						     Expressions evaluated as per pass 2.
;
; ************************************************************************************************

AXIdentifyAddressMode:

		; ----------------------------------------------------------------------------------------
		;
		;							First check for ASL/ASL A
		;
		; ----------------------------------------------------------------------------------------

		jsr 	AXGet 						; has two formats, ASL and ASL A
		cmp 	#0
		beq 	_AXIsAccumulator
		cmp 	#'A'
		bne 	_AXCheckImmediate

		lda 	AXBuffer+1,x 				; is the A followed by space/eol
		cmp 	#' '+1
		bcs 	_AXCheckImmediate
_AXIsAccumulator:
		lda 	#AXMAccumulator
		sta 	AXAddrMode
_AXIsOkay:
		clc
_AXExit:
		rts

		; ----------------------------------------------------------------------------------------
		;
		;							Check for Immediate and Indirect
		;
		; ----------------------------------------------------------------------------------------

_AXCheckImmediate:
		cmp 	#'#' 						; immediate
		beq 	_AXIsImmediate
		cmp	 	#'('						; indirect
		beq 	_AXIsIndirect
		;
		; ----------------------------------------------------------------------------------------
		;
		;								nnnn nnnn,x or nnnn,y
		;
		; ----------------------------------------------------------------------------------------

		jsr 	AXPass2Expression 			; evaluate base address
		bcs 	_AXExit 					; error in that.
		jsr 	AXGet 						; what follows
		beq 	_AXIsDirect 				; nothing, nnnn
		cmp 	#',' 						; if not needs to be ,X ,Y
		bne 	_AXSyntax
		inx
		jsr 	AXGet 						; what follows should be X or Y
		tay
		lda 	#AXMZeroX 					; check for ,X ,Y
		cpy 	#"X"
		beq 	_AXExitOkay
		lda 	#AXMZeroY
		cpy 	#"Y"
		beq 	_AXExitOkay
		;
_AXSyntax:
		lda 	#AXERRSyntax
		sec
		rts

_AXIsDirect:
		lda 	#AXMZero
_AXExitOkay:
		sta 	AXAddrMode
		clc
		rts

		; ----------------------------------------------------------------------------------------
		;
		;											Immediate
		;
		; ----------------------------------------------------------------------------------------

_AXIsImmediate:
		inx 								; consume the #
		jsr 	AXPass2Expression 			; get operand
		bcs 	_AXExit 					; bad operand

		lda 	#AXMImmediate 				; return immediate
		sta 	AXAddrMode
		clc
		rts

		; ----------------------------------------------------------------------------------------
		;
		; 							indirect (nnnn) (nnnn,x) or (nnnn),y
		;
		; ----------------------------------------------------------------------------------------

_AXIsIndirect:
		inx
		jsr 	AXPass2Expression 			; the address to indirect through
		jsr 	AXGet 						; what follows.
		cmp 	#"," 						; if , then check for indirect X
		beq 	_AXIndirectX
		cmp 	#")" 						; otherwise must be closing bracket
		bne 	_AXSyntax
		inx 								; consume )

		; ----------------------------------------------------------------------------------------
		;
		;						indirect (nnnn) or indirect y (nnnn),y
		;
		; ----------------------------------------------------------------------------------------

		jsr 	AXGet 						; if nothing follows it is (xxx)
		beq 	_AXIndirect
		cmp 	#","						; otherwise must be ,Y
		bne 	_AXSyntax
		inx
		jsr 	AXGet
		cmp 	#"Y"
		bne 	_AXSyntax
		;
		lda 	#AXMIndirectY 				; indirect Y
		sta 	AXAddrMode
		clc
		rts

_AXIndirect: 								; indirect
		lda 	#AXMIndirect
		sta 	AXAddrMode
		clc
		rts

		; ----------------------------------------------------------------------------------------
		;
		;								Indirect X (nnnn,x)
		;
		; ----------------------------------------------------------------------------------------

_AXIndirectX:
		inx 								; consume comma

		jsr 	AXGet 						; check x
		cmp 	#"X"
		bne 	_AXSyntax

		inx
		jsr 	AXGet 						; check )
		cmp 	#")"
		bne 	_AXSyntax

		lda 	#AXMIndirectX 				; it's indirect X
		sta 	AXAddrMode
		clc
		rts

		.send as16code

		.section as16storage
AXAddrMode:
		.fill 	1
		.send as16storage

; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		assemble.asm
;		Purpose:	Assemble a line from the source
;		Created:	12th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;				Assemble line in buffer. Returns CS on error, error code in A.
;
; ************************************************************************************************

AXAssembleLine:
		stz 	AXListCount					; clear the listing bytes.
		ldx 	#0 							; start of line
_AXAContinue:
		jsr 	AXGet 						; get first character
		clc 								; if 0, empty line, exit with carry clear
		beq 	_AXExit

		; ========================================================================================
		;
		;				Two options , it's * = <xxxx> or a label/instruction
		;
		; ========================================================================================

		cmp 	#'*' 						; is it * (for * = )
		beq 	_AXSetPC
		;
		jsr 	AXExtractIdentifier 		; get an identifier
		bcs 	_AXSyntax 					; if none found, report it as a syntax error.

		; ========================================================================================
		;
		;					Check if it's a system word, if so, process that.
		;
		; ========================================================================================

		phx 								; look in system dictionary (opcodes, pseudo ops etc).
		ldx 	#AXSystemDictionary & $FF
		ldy 	#AXSystemDictionary >> 8
		jsr 	AXIFind
		plx
		bcs 	_AXALabel 					; not found, label check.
		;
		phx
		ldy 	#AXID_Type 					; get the type
		jsr 	AXIGet
		plx
		;
		cmp 	#AXIT_Opcode 				; different code for opcode, macro, pseudo-op.
		beq 	_AXAOpcode
		cmp 	#AXIT_Macro
		beq 	_AXAMacro
		cmp 	#AXIT_PsuedoOp
		bne 	_AXSyntax
		;
		; ========================================================================================
		;
		;								Handle pseudo-operations
		;
		; ========================================================================================

		stx 	AXOperandPos 				; save the operand position.
		ldy 	#AXID_DataLow 				; get the code address and jump there.
		jsr 	AXIGet
		sta 	AXVector
		ldy 	#AXID_DataHigh
		jsr 	AXIGet
		sta 	AXVector+1
		jmp 	(AXVector)

		;
		jmp 	$FFFF 						; load the address and jump to it.
_AXAMacro:
		jmp 	AXPAssembleMacro
_AXAOpcode:
		jmp 	AXPAssembleOpcode

		; ========================================================================================
		;
		;					Not a mnemonic, so it's a label of some sort.
		;
		; ========================================================================================

_AXALabel:
		phx
		ldy 	AXIBase 					; start scanning.
		ldx 	#0
		jsr 	AXICreateFind 				; find it, or create it if necessary.
		plx

		jsr 	AXProcessLabel 				; process the label.
		bcc 	_AXAContinue 				; if okay, try the line again.
		rts 								; return with error.

		; ========================================================================================
		;
		;								Set the PC (* = <expr>)
		;
		; ========================================================================================
_AXSetPC:
		inx 	 							; get next.
		jsr 	AXGet
		cmp 	#'=' 						; must be equals.
		bne 	_AXSyntax
		inx
		jsr 	AXExpressionDefined 		; get an expression, must be defined.
		bcs 	_AXExit 					; error of some sort.

		lda 	AXLeft 						; copy result to current PC
		sta 	AXProgramCounter
		lda 	AXLeft+1
		sta 	AXProgramCounter+1
		clc 								; and done successfully.
		rts

_AXSyntax:
		lda 	#AXERRSyntax
		sec
_AXExit:
		rts

; ************************************************************************************************
;
;			Label (e.g. unknown identifier) in buffer. Decide what to do with it
;
; ************************************************************************************************

AXProcessLabel:
		jsr 	AXGet 						; what is next
		beq 	_AXLabelPC 					; nothing, it's a program counter label
		cmp 	#':'						; if label: then it's a program counter label.
		beq 	_AXPCTR 					; (we have to consume the :)
		jsr 	AXIsIdentifierHead 			; some identifier follows.
		bcc 	_AXLabelPC 					; then it's a program counter label.
		;
		inx 								; consume it anyway.
		cmp 	#'=' 						; must be '=' something
		beq 	_AXAssignValue 				; yes, assign value
		;
		lda 	#AXERRSyntax 				; otherwise syntax error
		sec
_AXPExit:
		rts

		; ========================================================================================
		;
		;				It's a label PC e.g. <label> <command> or <label>:
		;
		; ========================================================================================

_AXPCTR:
		inx 								; consume :
_AXLabelPC:
		phx 								; save position
		ldx 	AXProgramCounter
		ldy 	AXProgramCounter+1
		jsr 	AXIPutData 					; write it.
		plx 								; restore position
		rts 								; return with that error code.

		; ========================================================================================
		;
		;							It's label = <expression>
		;
		; ========================================================================================

_AXAssignValue:
		lda 	AXCurrent 					; save current identifier
		pha
		lda 	AXCurrent+1
		pha

		jsr 	AXExpressionDefined 		; evaluate expression

		pla 								; restore current identifier.
		sta 	AXCurrent+1
		pla
		sta 	AXCurrent

		bcs 	_AXPExit 					; exit on error.

		phx
		ldx 	AXLeft 						; set to the result
		ldy 	AXLeft+1 					; preserving X
		jsr 	AXIPutData
		plx
		rts

		.send as16code

		.section as16storage
AXOperandPos: 								; data in buffer starts here.
		.fill 	1
AXVector: 									; for calling psuedo op code
		.fill 	2
		.send as16storage

; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		file.asm
;		Purpose:	Assemble a single file
;		Created:	12th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;									Assemble file, YX is file name/NULL
;
; ************************************************************************************************

AXAssembleFile:
		lda 	#AXAPIOpen 					; open the source file.
		jsr 	AXCallAPI
		sta 	AXFileHandle 				; save handle
		lda 	#AXERRNotFound 				; return not found if failed.
		bcs 	_AXAFExit
		;
		stz 	AXLastCharacter 			; no last character
		stz 	AXLineNumber 				; reset line numbers
		stz 	AXLineNumberDecimal
		stz 	AXLineNumber+1
		stz 	AXLineNumberDecimal+1
		;
		;		The main assembler loop.
		;
_AXMainLoop:
		lda 	AXProgramCounter 			; copy program counter to program counter start
		sta 	AXProgramCounterStart 		; this is the value used in the unary function *
		lda 	AXProgramCounter+1
		sta 	AXProgramCounterStart+1
		lda 	AXProgramCounter+2
		sta 	AXProgramCounterStart+2
		;
		jsr 	AXReadLine 					; read the next line
		bcs 	_AXAFError 					; exit if problem (e.g. too long/eof)

		jsr 	AXAssembleLine 				; assemble it.
		bcs 	_AXAFError 					; exit if problem there.

		jsr 	AXListLine 					; list the line.
		bra 	_AXMainLoop

		;
		;		Come here on error *or* EOF
		;
_AXAFError:
		cmp 	#AXERREOF 					; was the error EOF, which isn't an error :)
		clc 								; if so don't report an error.
		beq 	_AFAXCloseExit

		sta 	AXErrorCode 				; save errorcode
		ldy 	#AXErrorCode >> 8 			; YX = error area.
		ldx 	#AXErrorCode & $FF
		lda 	#AXAPIError
		jsr 	AXCallAPI 			 		; returns CS if always exit.
		lda 	AXErrorCode 				; if error code is fatal, e.g. bit 7 set
		bpl 	_AFAXCloseExit
		sec 								; you cannot override it.

_AFAXCloseExit:
		php 								; save error flag and error ID
		pha
		lda 	#AXAPIClose 				; close the file.
		ldx 	AXFileHandle
		jsr 	AXCallAPI
		pla 								; restore flag/id and exit.
		plp
_AXAFExit:
		rts

; ************************************************************************************************
;
;										Call the API function
;
; ************************************************************************************************

AXCallAPI:
		jmp 	(AXAPI)

		.send as16code


