; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		group1.asm
;		Purpose:	Assemble group 1 (lda,sta,adc,cmp,sbc,and,eor,ora)
;		Created:	17th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;								Assemble group 1 instruction
;
; ************************************************************************************************

AXGroup1:
		jsr 	AXIdentifyAddressMode 		; get the address mode
		bcs 	_AXG1Exit 		 			; syntax error.

		jsr 	AXGroup1Assemble 			; assemble group 1 with ZP/# mods.
		bcc 	_AXG1Exit 					; it worked.
		jsr 	AXPromoteMode 				; promote mode.
		bcs 	_AXG1Exit 					; failed to promote.
		jsr 	AXGroup1Assemble 			; try it with absolute mode.

_AXG1Exit:
		rts

; ************************************************************************************************
;
;		Try to assemble with current mode. If ZP check range. CS if failed, CC if succeeded.
;								(should return error on STA #)
;
;		Note, the initial 8 modes are slightly different for the Group 1 set, see spreadsheet.
;
; ************************************************************************************************

AXGroup1Assemble:
		lda 	AXAddrMode 					; get address mode
		cmp	 	#AXMIndirectX 				; we support indirect X
		beq 	_AXG1ModeOk
		cmp 	#AXMIndirect 				; and indirect
		beq 	_AXG1ModeOk
		;
		cmp 	#AXMAccumulator 			; A is not supported.
		beq 	_AXG1Fail 					; other than that, just 0-7.
		and 	#$1F
		cmp 	#8
		bcs 	_AXG1Fail
		;
_AXG1ModeOk:
		lda 	AXAddrMode 					; does the mode support 3 byte.
		bpl 	_AXGOperandOk 				; if so, we can't reject for being ZP.

		lda 	AXLeft+1 					; fail if not a zero page instruction.
		bne 	_AXG1Fail
_AXGOperandOk:

		lda 	AXAddrMode 					; map (nn,x) onto 0 and # onto 2 because
		tax 								; group 1 is structured slightly differently.
		cpx 	#AXMImmediate
		bne 	_AXGNotImmediate
		lda 	#2
_AXGNotImmediate:
		cpx 	#AXMIndirectX
		bne 	_AXGNotIX
		lda 	#0
_AXGNotIX:
		cpx 	#AXMIndirect
		bne 	_AXGNotIndirect
		clc 								; indirect, add $11 to opcode
		lda 	#$11
		bra 	_AXGAddOpcode

_AXGNotIndirect:
		and 	#$1F 						; now a 0-7 address mode, x 4 and add the base opcode
		asl 	a
		asl 	a
_AXGAddOpcode:
		adc 	AXBaseOpcode
		cmp 	#$89 						; cannot sta #
		beq 	_AXG1Fail
		jsr 	AXWriteByte 				; write out the opcode.
		jsr 	AXWriteOperand 				; write the operand appropriately
		clc
		rts

_AXG1Fail:
		lda 	#AXERRMode 					; bad mode error.
		sec
		rts

; ************************************************************************************************
;
;						Write operand in AXLeft according to AXAddrMode
;
; ************************************************************************************************

AXWriteOperand:
		lda 	AXAddrMode 					; if Accumulator mode exit
		cmp 	#AXMAccumulator
		beq 	_AXWIs2Byte

		lda 	AXLeft 						; output LSB
		jsr 	AXWriteByte
		lda 	AXAddrMode
		bmi 	_AXWIs2Byte
		lda 	AXLeft+1 					; output MSB if wanted.
		jsr 	AXWriteByte
_AXWIs2Byte:
		rts

		.send as16code

; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		group2.asm
;		Purpose:	Assemble group 2 (ldx, asl and similar)
;		Created:	17th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;								Assemble group 2 instruction
;
; ************************************************************************************************

AXGroup2:
		jsr 	AXIdentifyAddressMode 		; get the address mode
		bcs 	_AXG2Exit 		 			; syntax error.

		jsr 	AXGroup2Assemble 			; assemble group2
		bcc 	_AXG2Exit 					; it worked.
		jsr 	AXPromoteMode 				; promote mode.
		bcs 	_AXG2Exit 					; failed to promote.
		jsr 	AXGroup2Assemble 			; try it with absolute mode.

_AXG2Exit:
		rts

; ************************************************************************************************
;
;		Try to assemble with current mode. If ZP check range. CS if failed, CC if succeeded.
;								(should return error on STA #)
;
;		Also test against the Fixup table which contains all the oddities.
;
; ************************************************************************************************

AXGroup2Assemble:
		lda 	AXAddrMode 					; get the address mode
		and 	#$1F 						; if >= 8 will be in the oddballs table
		cmp 	#8
		bcs 	_AX2CheckFixupList
		tax
		lda 	AXSelector					; bit pattern showing what is supported, what isn't.
_AXG2CheckSelector: 						; shift the mode enabled bit into the carry
		asl 	a
		dex
		bpl 	_AXG2CheckSelector
		bcc 	_AX2CheckFixupList 			; not supported.
		;
		lda 	AXAddrMode 					; if it is not zero page, then it's okay.
		bpl 	_AX2IsOkay
		lda 	AXLeft+1 					; okay if zero page, and < 256
		bne 	_AX2Fail
_AX2IsOkay:
		lda 	AXAddrMode 					; mode x 4
		and 	#$1F
		asl 	a
		asl 	a
		adc 	AXBaseOpcode
		jsr 	AXWriteByte 				; write out the opcode.
		jsr 	AXWriteOperand 				; write the operand appropriately,
		clc
		rts
		;
		;		Didn't work. Let's try this mode and base opcode against ehf dix up list.
		;
_AX2CheckFixupList:
		lda 	AXAddrMode 					; fail if zero page address mode and non-zp operand.
		bpl 	_AX2CheckFixup
		lda 	AXLeft+1
		bne 	_AX2Fail
_AX2CheckFixup:
		ldx 	#0
_AX2FixupLoop:
		lda 	AXGroup2OpcodeFixupTable,x 	; base opcode
		beq 	_AX2Fail
		cmp 	AXBaseOpcode 				; if opcodes dont match go to next.
		bne 	_AX2Next
		lda 	AXGroup2OpcodeFixupTable+1,x; address mode
		cmp 	AXAddrMode
		beq 	_AX2Found 					; found a match
_AX2Next:
		inx 								; next table entry
		inx
		inx
		bra 	_AX2FixupLoop
		;
_AX2Found:
		lda 	AXGroup2OpcodeFixupTable+2,x ; get actual opcode
		jsr 	AXWriteByte
		jsr 	AXWriteOperand 				; write the operand appropriately,
		clc
		rts

_AX2Fail:
		lda 	#AXERRMode 					; bad mode error.
		sec
		rts

		.send as16code

; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		group3.asm
;		Purpose:	Assemble group 3 instruction (relative branches)
;		Created:	17th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;								Assemble group 3 instruction
;
; ************************************************************************************************

AXGroup3:
		lda 	AXBaseOpcode 				; assemble the base opcode.
		jsr 	AXWriteByte
		;
		jsr 	AXPass2Expression 			; get expression defined on pass 2.
		bcs 	_AXG3Exit
		;
		lda 	AXPass 						; pass 1, don't care.
		cmp 	#1
		beq 	_AXOutputOffset

		clc  								; calculate relative branch
		lda 	AXLeft 						; we have one too many because of the opcode
		sbc 	AXProgramCounter 			; so we clc here to borrow one.
		tax
		lda 	AXLeft+1
		sbc 	AXProgramCounter+1
		tay

		cpx 	#0 							; for 00-7F Y should be 0, for 80-FF it should be $FF
		bpl 	_AXNotBack 					; if we bump Y if X is -ve, then if zero it's a fail.
		iny
_AXNotBack:
		cpy 	#0 							; so check it
		beq 	_AXOutputOffset
		;
		sec  								; if it's not out of range
		lda 	#AXERRRelative
		bra 	_AXG3Exit
		;
_AXOutputOffset:
		txa
		jsr 	AXWriteByte 				; output the offset
		clc
_AXG3Exit:
		rts

		.send as16code

; ************************************************************************************************
;
;									Changes and Updates
