; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		divide.asm
;		Purpose:	16 bit divide (unsigned)
;		Created:	10th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code


; ************************************************************************************************
;
;							Calculate Left := Left / Right
;
; ************************************************************************************************

AXBinaryDivide: ;; [/]
		lda 	AXRight 					; check divide by zero
		ora 	AXRight+1
		beq 	_AXDivZero
		;
		stz 	AXDTemp 					; A = 0
		stz 	AXDTemp+1
		;
		ldy 	#16 						; iteration count.
_AXDivLoop:
		phy
		;
		asl 	AXLeft 						; shift AQ left.
		rol 	AXLeft+1
		rol 	AXDTemp
		rol 	AXDTemp+1
		;
		sec 								; A-M => A:Y
		lda 	AXDTemp
		sbc 	AXRight
		tay
		lda 	AXDTemp+1
		sbc 	AXRight+1
		bcc 	_AXDivNext 					; if A < M exit
		;
		sta 	AXDTemp+1 					; A = A - M
		sty 	AXDTemp
		inc 	AXLeft 						; set bit 0 of the result.
_AXDivNext:
		ply
		dey
		bne 	_AXDivLoop
		clc
		rts

_AXDivZero:
		lda 	#AXERRDivZero
		sec
		rts

; ************************************************************************************************
;
;							Calculate Left := Left % Right
;
; ************************************************************************************************

AXBinaryModulus: ;; [%]
		jsr 	AXBinaryDivide
		bcs 	_AXBMExit
		lda 	AXDTemp
		sta 	AXLeft
		lda 	AXDTemp+1
		sta 	AXLeft+1
		clc
_AXBMExit:
		rts

		.send as16code

		.section as16storage
AXDTemp:
		.fill 	2
		.send as16storage

; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		multiply.asm
;		Purpose:	16 bit multiply
;		Created:	9th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code


; ************************************************************************************************
;
;							Calculate Left := Left * Right
;
; ************************************************************************************************

AXBinaryMult: ;; [*]
		lda 	AXLeft 						; copy left to temp
		sta 	AXMTemp
		lda 	AXLeft+1
		sta 	AXMTemp+1
		stz 	AXLeft	 					; zero left
		stz 	AXLeft+1
_AXMultLoop:
		lda 	AXMTemp 					; bit 0 of old left set ?
		and 	#1
		beq 	_AXNoAdd
		jsr 	AXBinaryAdd					; add right to left
_AXNoAdd:
		asl 	AXRight 					; shift right left
		rol 	AXRight+1
		lsr 	AXMTemp+1 					; shift old left right
		ror 	AXMTemp
		;
		lda 	AXMTemp 					; loop back if old left still non-zero
		ora 	AXMTemp+1
		bne 	_AXMultLoop
		clc
		rts

		.send as16code

		.section as16storage
AXMTemp:
		.fill 	2
		.send as16storage

; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		shift.asm
;		Purpose:	Bit shifting binary operators.
;		Created:	9th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;							Calculate Left := Left >> or << Right
;
; ************************************************************************************************

AXShiftLeft: ;; [<<]
		ldy 	#0
		bra 	AXShiftMain
AXShiftRight: ;; [>>]
		ldy 	#$FF
AXShiftMain:
		lda 	AXRight 					; if shift > 15 then zero
		and 	#$F0
		ora 	AXRight+1
		bne 	_AXShiftZero
		;
		lda 	AXRight 					; shift zero, exit as unchanged.
		beq 	_AXExit
		;
_AXShiftLoop:
		cpy 	#0 							; shift depending on direction flag in Y
		beq 	_AXShiftLeft
		lsr 	AXLeft+1
		ror 	AXLeft
		bra 	_AXShiftNext
_AXShiftLeft:
		asl 	AXLeft
		rol 	AXLeft+1
_AXShiftNext:
		dec 	AXRight 					; do required # of times
		bne 	_AXShiftLoop
		clc 								; exit okay.
		rts

_AXShiftZero:
		stz 	AXLeft
		stz 	AXLeft+1
_AXExit:
		clc
		rts

; ************************************************************************************************
;
;									Swap left and right
;
; ************************************************************************************************

AXSwap:
		pha
		phx
		lda 	AXRight
		ldx 	AXLeft
		sta 	AXLeft
		stx 	AXRight

		lda 	AXRight+1
		ldx 	AXLeft+1
		sta 	AXLeft+1
		stx 	AXRight+1

		lda 	AXRight+2
		ldx 	AXLeft+2
		sta 	AXLeft+2
		stx 	AXRight+2

		plx
		pla
		rts

		.send as16code


; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		simple.asm
;		Purpose:	Simple arithmetic (all unsigned)
;		Created:	9th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

binop	.macro
		lda		AXLeft
		\1 		AXRight
		sta 	AXLeft
		lda		AXLeft+1
		\1 		AXRight+1
		sta 	AXLeft+1
		clc 								; no error.
		.endm

; ************************************************************************************************
;
;							Calculate Left :=  Left + Right
;
; ************************************************************************************************

AXBinaryAdd: ;; [+]
		clc
		.binop 	adc
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left - Right
;
; ************************************************************************************************

AXBinarySub: ;; [-]
		sec
		.binop 	sbc
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left AND Right
;
; ************************************************************************************************

AXBinaryAnd: ;; [&]
		.binop 	and
		rts


; ************************************************************************************************
;
;							Calculate Left :=  Left OR Right
;
; ************************************************************************************************

AXBinaryOra: ;; [|]
		.binop 	ora
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left AND Right
;
; ************************************************************************************************

AXBinaryEor: ;; [^]
		.binop 	eor
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left <> Right
;
; ************************************************************************************************

AXBinaryNotEqual: ;; [<>]
		jsr 	AXBinaryEor
		lda 	AXLeft
		ora 	AXLeft+1
		beq 	_AXBEExit
		lda 	#$FF
_AXBEExit:
		sta 	AXLeft
		sta 	AXLeft+1
		clc
		rts

; ************************************************************************************************
;
;							Calculate Left :=  Left = Right
;
; ************************************************************************************************

AXBinaryEqual: ;; [=]
		jsr 	AXBinaryNotEqual
		bra 	AXNot

; ************************************************************************************************
;
;								Calculate Left := Left > Right
;
; ************************************************************************************************

AXGreater: ;; [>]
		jsr 	AXSwap

; ************************************************************************************************
;
;								Calculate Left := Left < Right
;
; ************************************************************************************************

AXLess: ;; [<]
		lda 	AXLeft
		cmp 	AXRight
		lda 	AXLeft+1
		sbc 	AXRight+1
		lda 	#$00
		bcs 	_AXIsGtr
		dec 	a
_AXIsGtr:
		sta 	AXLeft
		sta 	AXLeft+1
		clc
		rts

; ************************************************************************************************
;
;								Calculate Left := Left <= / >= Right
;
; ************************************************************************************************

AXLessEqual: ;; [<=]
		jsr 	AXGreater
		bra 	AXNot

AXGreaterEqual: ;; [>=]
		jsr 	AXLess
		bra 	AXNot

; ************************************************************************************************
;
;										Left := ~ Left
;
; ************************************************************************************************

AXNot:
		lda 	AXLeft
		eor 	#$FF
		sta 	AXLeft
		sta 	AXLeft+1
		clc
		rts

		.send as16code

