; ************************************************************************************************

AXFillCmd:	;; {.fill}
AXFillCmd2:	;; {.ds}
		ldx 	AXOperandPos 				; get operand, must be defined even on pass 1.
		jsr 	AXExpressionDefined
		bcs 	_AXFExit 					; didn't work.
		;
		clc
		lda 	AXProgramCounter
		adc 	AXLeft
		sta 	AXProgramCounter
		lda 	AXProgramCounter+1
		adc 	AXLeft+1
		sta 	AXProgramCounter+1
		clc
_AXFExit:
		rts

		.send as16code

